import android.util.Log
import timber.log.Timber
import java.util.regex.Pattern

class ProductionLogger {
    companion object {
        private const val TAG = "ProductionLogger"
        private val SECRET_PATTERN = Pattern.compile(
            "(?i)(api[_-]?key|token|password|secret|access[_-]?token|auth[_-]?token|session[_-]?id|jwt|oauth|client[_-]?id|client[_-]?secret|refresh[_-]?token|authorization)" +
            "\\s*[:=]\\s*[\"']?([^\"'\\s]+)[\"']?",
            Pattern.CASE_INSENSITIVE
        )
        
        private val PERSONAL_DATA_PATTERN = Pattern.compile(
            "(?i)(email|phone|phone[_-]?number|ssn|credit[_-]?card|card[_-]?number|user[_-]?id|user[_-]?name|full[_-]?name|address|city|state|zip|country)" +
            "\\s*[:=]\\s*[\"']?([^\"'\\s]+)[\"']?",
            Pattern.CASE_INSENSITIVE
        )
        
        fun logAuthAttempt(success: Boolean, userId: String?, details: Map<String, Any>?) {
            try {
                val sanitizedDetails = sanitizeMap(details ?: emptyMap())
                val userIdSanitized = sanitizeString(userId)
                
                if (success) {
                    Timber.tag(TAG).v("AUTH_SUCCESS - User: %s, Details: %s", userIdSanitized, sanitizedDetails)
                } else {
                    Timber.tag(TAG).w("AUTH_FAILURE - User: %s, Details: %s", userIdSanitized, sanitizedDetails)
                }
            } catch (e: Exception) {
                Timber.tag(TAG).e(e, "Failed to log auth attempt")
            }
        }
        
        fun logDatabaseQuery(query: String, params: List<Any>?) {
            try {
                val sanitizedQuery = sanitizeString(query)
                val sanitizedParams = params?.map { sanitizeString(it.toString()) } ?: emptyList()
                
                Timber.tag(TAG).v("DB_QUERY - Query: %s, Params: %s", sanitizedQuery, sanitizedParams)
            } catch (e: Exception) {
                Timber.tag(TAG).e(e, "Failed to log database query")
            }
        }
        
        fun logApiRequest(url: String, method: String, headers: Map<String, String>?, body: String?) {
            try {
                val sanitizedUrl = sanitizeString(url)
                val sanitizedHeaders = sanitizeMap(headers ?: emptyMap())
                val sanitizedBody = sanitizeString(body ?: "")
                
                Timber.tag(TAG).v(
                    "API_REQUEST - Method: %s, URL: %s, Headers: %s, Body: %s",
                    method, sanitizedUrl, sanitizedHeaders, sanitizedBody
                )
            } catch (e: Exception) {
                Timber.tag(TAG).e(e, "Failed to log API request")
            }
        }
        
        fun logApiResponse(url: String, statusCode: Int, headers: Map<String, String>?, body: String?) {
            try {
                val sanitizedUrl = sanitizeString(url)
                val sanitizedHeaders = sanitizeMap(headers ?: emptyMap())
                val sanitizedBody = sanitizeString(body ?: "")
                
                Timber.tag(TAG).v(
                    "API_RESPONSE - URL: %s, Status: %d, Headers: %s, Body: %s",
                    sanitizedUrl, statusCode, sanitizedHeaders, sanitizedBody
                )
            } catch (e: Exception) {
                Timber.tag(TAG).e(e, "Failed to log API response")
            }
        }
        
        fun logException(e: Exception, context: String = "") {
            try {
                val sanitizedContext = sanitizeString(context)
                Timber.tag(TAG).e(e, "EXCEPTION - Context: %s", sanitizedContext)
            } catch (innerE: Exception) {
                Log.e(TAG, "Failed to log exception", innerE)
            }
        }
        
        private fun sanitizeString(input: String): String {
            if (input.isEmpty()) return input
            
            var sanitized = input
            
            // Remove secrets
            sanitized = SECRET_PATTERN.matcher(sanitized).replaceAll("$1=[REDACTED]")
            
            // Remove personal data
            sanitized = PERSONAL_DATA_PATTERN.matcher(sanitized).replaceAll("$1=[REDACTED]")
            
            // Remove common sensitive patterns
            sanitized = sanitized.replace(Regex("(?i)(\\b\\d{4}[-\\s]?\\d{4}[-\\s]?\\d{4}[-\\s]?\\d{4}\\b)"), "[REDACTED]")
            sanitized = sanitized.replace(Regex("(?i)(\\b\\d{3}[-\\s]?\\d{2}[-\\s]?\\d{4}\\b)"), "[REDACTED]")
            
            return sanitized
        }
        
        private fun sanitizeMap(map: Map<String, Any>): Map<String, String> {
            return map.mapValues { entry ->
                sanitizeString(entry.value.toString())
            }
        }
    }
}

